import {
  forwardRef,
  type RefObject,
  type ReactNode,
  type MouseEvent as ReactMouseEvent,
} from 'react';
import { createPortal } from 'react-dom';

import { chartTooltip, wrapper } from './BasicChartTooltip.sty.js';
import { useOverlayStacking } from '../../../../../../../core/hooks/useOverlayStacking.js';
import { OverlayStackingProvider } from '../../../../../../../core/providers/OverlayStackingProvider.js';
import { useDataDtrumContext } from '../../../../../context/DataDtrumContext.js';
import { TooltipAlignment } from '../../../shared/types/tooltip-shared.js';

export type BasicChartTooltipProps = {
  /** Whether the chart tooltipmarker is on the right or left side.
   * @defaultValue 'left'
   */
  placement?: TooltipAlignment;
  children?: ReactNode;
  /* The reference to the timeseries chart container */
  chartRef?: RefObject<HTMLDivElement>;
  onMouseLeave?: (event: ReactMouseEvent) => void;
  pinned?: boolean;
};

/**
 * ChartsTooltip component
 */
export const BasicChartTooltip = /* @__PURE__ */ forwardRef<
  HTMLDivElement,
  BasicChartTooltipProps
>((props, forwardedRef) => {
  const {
    placement = 'left',
    children,
    chartRef,
    onMouseLeave,
    pinned = false,
  } = props;

  const { dataDtrumMask, dataDtrumAllow } = useDataDtrumContext();
  const overlayStacking = useOverlayStacking(0, 'overlay');

  const chartTooltipContent = (
    <div
      className={wrapper({ isPinned: pinned })}
      style={{ zIndex: overlayStacking.style.zIndex }}
      data-testid="chart-tooltip"
      role="tooltip"
      ref={forwardedRef}
      data-placement={placement}
      data-dtrum-mask={dataDtrumMask}
      data-dtrum-allow={dataDtrumAllow}
      onMouseLeave={onMouseLeave}
    >
      <OverlayStackingProvider>
        <div className={chartTooltip}>{children}</div>
      </OverlayStackingProvider>
    </div>
  );

  // The tooltip will be placed in the body if no reference is passed
  const placementNode = chartRef
    ? (chartRef.current as HTMLDivElement)
    : document.body;

  return createPortal(chartTooltipContent, placementNode);
});

(
  BasicChartTooltip as typeof BasicChartTooltip & { displayName: string }
).displayName = 'BasicChartTooltip';
